412	// GetRunsGraphQL implements RunsStateProvider.
413	func (s *ServerState) GetRunsGraphQL(projectID string, filter ddxgraphql.RunFilter) []*ddxgraphql.Run {
414		var all []*ddxgraphql.Run
415	
416		if projectID != "" {
417			proj, ok := s.GetProjectByID(projectID)
418			if !ok {
419				return nil
420			}
421			all = s.loadRunsForProject(projectID, proj.Path)
422		} else {
423			for _, proj := range s.GetProjects(false) {
424				all = append(all, s.loadRunsForProject(proj.ID, proj.Path)...)
425			}
426			sort.Slice(all, func(i, j int) bool {
427				si, sj := "", ""
428				if all[i].StartedAt != nil {
429					si = *all[i].StartedAt
430				}
431				if all[j].StartedAt != nil {
432					sj = *all[j].StartedAt
433				}
434				return si > sj
435			})
436		}
437		return ddxgraphql.ApplyRunFilter(all, filter)
438	}
