39	// makeRunWithHarness creates a run-layer Run with a custom harness.
40	func makeRunWithHarness(id string, layer ddxgraphql.RunLayer, status, harness string) *ddxgraphql.Run {
41		r := makeRun(id, layer, status)
42		if layer == ddxgraphql.RunLayerRun {
43			r.Harness = &harness
44		}
45		return r
46	}
