48	// makeRun creates a Run fixture for the given layer.
49	func makeRun(id string, layer ddxgraphql.RunLayer, status string) *ddxgraphql.Run {
50		now := time.Now().UTC().Format(time.RFC3339)
51		run := &ddxgraphql.Run{
52			ID:          id,
53			Layer:       layer,
54			Status:      status,
55			StartedAt:   &now,
56			ChildRunIds: []string{},
57		}
58		switch layer {
59		case ddxgraphql.RunLayerWork:
60			qi := `{"beads":["ddx-001","ddx-002"]}`
61			sc := "drain-all"
62			run.QueueInputs = &qi
63			run.StopCondition = &sc
64			run.SelectedBeadIds = []string{"ddx-001", "ddx-002"}
65			child1 := "try-001"
66			run.ChildRunIds = []string{child1}
67		case ddxgraphql.RunLayerTry:
68			bead := "ddx-001"
69			base := "abc123"
70			result := "def456"
71			wt := ".ddx/worktrees/try-001"
72			mo := "merged"
73			run.BeadID = &bead
74			run.BaseRevision = &base
75			run.ResultRevision = &result
76			run.WorktreePath = &wt
77			run.MergeOutcome = &mo
78			parent := "work-001"
79			run.ParentRunID = &parent
80			child1 := "run-001"
81			run.ChildRunIds = []string{child1}
82		case ddxgraphql.RunLayerRun:
83			bead := "ddx-001"
84			harness := "claude"
85			provider := "anthropic"
86			model := "claude-sonnet-4-6"
87			in := 1000
88			out := 500
89			dur := 12000
90			cost := 0.015
91			excerpt := "Task completed successfully."
92			run.BeadID = &bead
93			run.Harness = &harness
94			run.Provider = &provider
95			run.Model = &model
96			run.TokensIn = &in
97			run.TokensOut = &out
98			run.DurationMs = &dur
99			run.CostUsd = &cost
100			run.OutputExcerpt = &excerpt
101			run.EvidenceLinks = []string{".ddx/executions/20260501T010000-aabbccdd"}
102			parent := "try-001"
103			run.ParentRunID = &parent
104		}
105		return run
106	}
