108	// TestIntegration_Query_Runs covers list, layer filter, detail, and parent/child paths.
109	func TestIntegration_Query_Runs(t *testing.T) {
110		workDir, store := setupIntegrationDir(t)
111		base := newTestStateProvider(workDir, store)
112		projID := base.projects[0].ID
113	
114		workRun := makeRun("work-001", ddxgraphql.RunLayerWork, "success")
115		tryRun := makeRun("try-001", ddxgraphql.RunLayerTry, "success")
116		runRun := makeRun("run-001", ddxgraphql.RunLayerRun, "success")
117		runFail := makeRunWithHarness("run-002", ddxgraphql.RunLayerRun, "failure", "codex")
118	
119		provider := &runsTestProvider{
120			testStateProvider: base,
121			all:               []*ddxgraphql.Run{workRun, tryRun, runRun, runFail},
122		}
123		h := newGQLHandler(provider, workDir, nil)
124	
