450	// with synthesized execution bundle records.
451	func (s *ServerState) loadRunsForProject(projectID, projectRoot string) []*ddxgraphql.Run {
452		// Primary: FEAT-010 run store
453		stored := scanRunStore(projectRoot)
454	
455		// Secondary: synthesize run-layer records from .ddx/executions/ bundles,
456		// but only include IDs that are not already in the stored set.
457		storedIDs := make(map[string]bool, len(stored))
458		for _, r := range stored {
459			storedIDs[r.ID] = true
460		}
461	
462		synthesized := synthesizeRunsFromBundles(projectID, projectRoot)
463		for _, r := range synthesized {
464			if !storedIDs[r.ID] {
465				stored = append(stored, r)
466				storedIDs[r.ID] = true
467			}
468		}
469	
470		sessions := synthesizeRunsFromSessions(projectID, projectRoot)
471		for _, r := range sessions {
472			if !storedIDs[r.ID] {
473				stored = append(stored, r)
474				storedIDs[r.ID] = true
475			}
476		}
477	
478		// Sort newest-first by startedAt.
479		sort.Slice(stored, func(i, j int) bool {
480			si, sj := "", ""
481			if stored[i].StartedAt != nil {
482				si = *stored[i].StartedAt
483			}
484			if stored[j].StartedAt != nil {
485				sj = *stored[j].StartedAt
486			}
487			return si > sj
488		})
489		return tagProjectID(stored, projectID)
490	}
