// loadRunsForProject loads runs for a single project, merging the file store
// with synthesized execution bundle records.
func (s *ServerState) loadRunsForProject(projectID, projectRoot string) []*ddxgraphql.Run {
	// Primary: FEAT-010 run store
	stored := scanRunStore(projectRoot)

	// Index stored records by ID. When a synthesized record shares an ID with
	// a stored record we must preserve both: the stored value wins for fields
	// it already populates, and the synthesized record fills in any gaps. This
	// gives the run resolver a lossless join with the AgentSession backing
	// store under layer=run (and with the bundle backing store under layer=try).
	byID := make(map[string]*ddxgraphql.Run, len(stored))
	for _, r := range stored {
		byID[r.ID] = r
	}

	synthesized := synthesizeRunsFromBundles(projectID, projectRoot)
	for _, r := range synthesized {
		if existing, ok := byID[r.ID]; ok {
			mergeRun(existing, r)
			continue
		}
		stored = append(stored, r)
		byID[r.ID] = r
	}

	sessions := synthesizeRunsFromSessions(projectID, projectRoot)
	for _, r := range sessions {
		if existing, ok := byID[r.ID]; ok {
			mergeRun(existing, r)
			continue
		}
		stored = append(stored, r)
		byID[r.ID] = r
	}

// mergeRun fills missing fields on dst from src. dst is treated as the
// authoritative record; src supplies values only where dst is unset. Used to
// realize a lossless join when a stored Run shares an ID with a record
// synthesized from the AgentSession or execute-bead bundle backing stores.
func mergeRun(dst, src *ddxgraphql.Run) {
	if dst == nil || src == nil {
		return
	}
	if dst.Status == "" && src.Status != "" {
		dst.Status = src.Status
	}
	if dst.StartedAt == nil && src.StartedAt != nil {
		dst.StartedAt = src.StartedAt
	}
	if dst.CompletedAt == nil && src.CompletedAt != nil {
		dst.CompletedAt = src.CompletedAt
	}
	if dst.BeadID == nil && src.BeadID != nil {
		dst.BeadID = src.BeadID
	}
	if dst.ArtifactID == nil && src.ArtifactID != nil {
		dst.ArtifactID = src.ArtifactID
	}
	if dst.ParentRunID == nil && src.ParentRunID != nil {
		dst.ParentRunID = src.ParentRunID
	}
	if len(dst.ChildRunIds) == 0 && len(src.ChildRunIds) > 0 {
		dst.ChildRunIds = src.ChildRunIds
	}
	// Try-layer fields
	if dst.BaseRevision == nil && src.BaseRevision != nil {
		dst.BaseRevision = src.BaseRevision
	}
	if dst.ResultRevision == nil && src.ResultRevision != nil {
		dst.ResultRevision = src.ResultRevision
	}
	if dst.WorktreePath == nil && src.WorktreePath != nil {
		dst.WorktreePath = src.WorktreePath
	}
	if dst.MergeOutcome == nil && src.MergeOutcome != nil {
		dst.MergeOutcome = src.MergeOutcome
	}
	if dst.CheckResults == nil && src.CheckResults != nil {
		dst.CheckResults = src.CheckResults
	}
	// Run-layer fields (sourced from AgentSession)
	if dst.PromptSummary == nil && src.PromptSummary != nil {
		dst.PromptSummary = src.PromptSummary
	}
	if dst.Harness == nil && src.Harness != nil {
		dst.Harness = src.Harness
	}
	if dst.Provider == nil && src.Provider != nil {
		dst.Provider = src.Provider
	}
	if dst.Model == nil && src.Model != nil {
		dst.Model = src.Model
	}
	if dst.TokensIn == nil && src.TokensIn != nil {
		dst.TokensIn = src.TokensIn
	}
	if dst.TokensOut == nil && src.TokensOut != nil {
		dst.TokensOut = src.TokensOut
	}
	if dst.CostUsd == nil && src.CostUsd != nil {
		dst.CostUsd = src.CostUsd
	}
	if dst.DurationMs == nil && src.DurationMs != nil {
		dst.DurationMs = src.DurationMs
	}
	if dst.OutputExcerpt == nil && src.OutputExcerpt != nil {
		dst.OutputExcerpt = src.OutputExcerpt
	}
	if len(dst.EvidenceLinks) == 0 && len(src.EvidenceLinks) > 0 {
		dst.EvidenceLinks = src.EvidenceLinks
	}
}

