// TestRunsLossless_StoredJoinsWithSession verifies that when a stored run
// record (FEAT-010 file store) shares an ID with an AgentSession entry, the
// resolver returns a single Run that carries the union of fields from both
// sources rather than dropping the session-derived projection.
func TestRunsLossless_StoredJoinsWithSession(t *testing.T) {
	workDir := t.TempDir()
	writeConfig(t, workDir, `version: "1.0"`+"\n")
	state := stateWithProject(workDir)

	// Stored run-layer record with only the prompt summary populated; harness,
	// model, tokens, etc. are absent and must be filled from the session.
	runDir := filepath.Join(workDir, runStoreDir)
	if err := os.MkdirAll(runDir, 0o755); err != nil {
		t.Fatal(err)
	}
	stored := []byte(`{"id":"sess-join-001","layer":"run","status":"running","prompt_summary":"draft prompt"}`)
	if err := os.WriteFile(filepath.Join(runDir, "sess-join-001.json"), stored, 0o644); err != nil {
		t.Fatal(err)
	}

	now := time.Date(2026, 4, 23, 1, 0, 0, 0, time.UTC)
	appendSummarySession(t, workDir, agent.SessionIndexEntry{
		ID:           "sess-join-001",
		BeadID:       "ddx-007",
		Harness:      "claude",
		Provider:     "anthropic",
		Model:        "claude-sonnet-4-6",
		BillingMode:  "subscription",
		StartedAt:    now,
		DurationMS:   8000,
		InputTokens:  321,
		OutputTokens: 654,
		CostUSD:      0.05,
		CostPresent:  true,
		Outcome:      "success",
	}, now)

	runs := state.GetRunsGraphQL("proj-test", ddxgraphql.RunFilter{})

	var joined *ddxgraphql.Run
	for _, r := range runs {
		if r.ID == "sess-join-001" {
			joined = r
			break
		}
	}
	if joined == nil {
		t.Fatal("expected a single Run for the shared id")
	}

	// Stored side wins: prompt_summary and "running" status survive.
	if joined.PromptSummary == nil || *joined.PromptSummary != "draft prompt" {
		t.Fatalf("stored promptSummary lost: %v", joined.PromptSummary)
	}
	if joined.Status != "running" {
		t.Fatalf("stored status lost: %q", joined.Status)
	}

	// Session side fills the gaps.
	if joined.Harness == nil || *joined.Harness != "claude" {
		t.Fatalf("session harness not joined: %v", joined.Harness)
	}
	if joined.Model == nil || *joined.Model != "claude-sonnet-4-6" {
		t.Fatalf("session model not joined: %v", joined.Model)
	}
	if joined.TokensIn == nil || *joined.TokensIn != 321 {
		t.Fatalf("session tokensIn not joined: %v", joined.TokensIn)
	}
	if joined.TokensOut == nil || *joined.TokensOut != 654 {
		t.Fatalf("session tokensOut not joined: %v", joined.TokensOut)
	}
	if joined.CostUsd == nil || *joined.CostUsd != 0.05 {
		t.Fatalf("session costUsd not joined: %v", joined.CostUsd)
	}
	if joined.DurationMs == nil || *joined.DurationMs != 8000 {
		t.Fatalf("session durationMs not joined: %v", joined.DurationMs)
	}
	if joined.BeadID == nil || *joined.BeadID != "ddx-007" {
		t.Fatalf("session beadId not joined: %v", joined.BeadID)
	}

	// Single record per id — no duplicate from the session-derived list.
	count := 0
	for _, r := range runs {
		if r.ID == "sess-join-001" {
			count++
		}
	}
	if count != 1 {
		t.Fatalf("expected 1 record for sess-join-001, got %d", count)
	}
}
